import React, { useState } from 'react';
import styled from 'styled-components';
import DatePicker from 'react-datepicker';
import 'react-datepicker/dist/react-datepicker.css';
import { useGlobalContext } from '../../context/globalContext';
import Button from '../Button/Button';
import { plus } from '../../utils/icons';

const Form = () => {
  const { addIncome, error } = useGlobalContext();

  const [inputState, setInputState] = useState({
    ingreso_id: '',
    usuario_id: '',
    fuente: '',
    monto: '',
    descripcion: '',
    fecha: '',
  });

  const { ingreso_id, usuario_id, fuente, monto, descripcion, fecha } = inputState;

  const handleInput = (name) => (e) => {
    setInputState({ ...inputState, [name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    addIncome({
      ingreso_id,
      usuario_id,
      fuente,
      monto: Number(monto),
      descripcion,
      fecha,
    });

    setInputState({
      ingreso_id: '',
      usuario_id: '',
      fuente: '',
      monto: '',
      descripcion: '',
      fecha: '',
    });
  };

  return (
    <FormStyled onSubmit={handleSubmit}>
      {error && <p className='error'>{error}</p>}

      <div className="input-control">
        <input
          type='text'
          value={ingreso_id}
          name='ingreso_id'
          placeholder='ID del ingreso'
          onChange={handleInput('ingreso_id')}
        />
      </div>

      <div className="input-control">
        <input
          type='text'
          value={usuario_id}
          name='usuario_id'
          placeholder='ID del usuario'
          onChange={handleInput('usuario_id')}
        />
      </div>

      <div className="selects input-controls">
        <select
          required
          value={fuente}
          name='fuente'
          id='fuente'
          onChange={handleInput('fuente')}
        >
          <option value="" disabled>Selecciona fuente</option>
          <option value="Salario">Salario</option>
          <option value="Freelance">Freelance</option>
          <option value="Ventas">Ventas</option>
          <option value="Inversion">Inversion</option>
          <option value="Transferencia">Transferencia</option>
          <option value="Otro">Otro</option>
        </select>
      </div>

      <div className="input-control">
        <input
          value={monto}
          type='number'
          name='monto'
          placeholder='Monto del ingreso'
          onChange={handleInput('monto')}
        />
      </div>

      <div className="input-control">
        <DatePicker
          id='fecha'
          placeholderText='Ingresa fecha'
          selected={fecha}
          dateFormat='dd/MM/yyyy'
          onChange={(date) => {
            setInputState({ ...inputState, fecha: date });
          }}
        />
      </div>

      <div className="input-control">
        <textarea
          name='descripcion'
          value={descripcion}
          placeholder='Descripción'
          id='descripcion'
          cols='30'
          rows='4'
          onChange={handleInput('descripcion')}
        />
      </div>

      <div className="submit-btn">
        <Button
          name={'Agregar Ingreso'}
          icon={plus}
          bPad={'.8rem 1.6rem'}
          bRad={'30px'}
          bg={'var(--color-accent)'}
          color={'#fff'}
        />
      </div>
    </FormStyled>
  );
};

const FormStyled = styled.form`
  display: flex;
  flex-direction: column;
  gap: 2rem;

  input, textarea, select{
    font-family: inherit;
    font-size: inherit;
    outline: none;
    border: none;
    padding: .5rem 1rem;
    border-radius: 5px;
    border: 2px solid #fff;
    background: transparent;
    resize: none;
    box-shadow: 0px 1px 15px rgba(0, 0, 0, 0.06);
    color: rgba(34, 34, 96, 0.9);

    &::placeholder{
      color: rgba(34, 34, 96, 0.4);
    }
  }

  .input-control{
    input{
      width: 100%;
    }
  }

  .selects{
    display: flex;
    justify-content: flex-end;

    select{
      color: rgba(34, 34, 96, 0.4);

      &:focus, &:active{
        color: rgba(34, 34, 96, 1);
      }
    }
  }

  .submit-btn{
    button{
      box-shadow: 0px 1px 15px rgba(0, 0, 0, 0.06);

      &:hover{
        background: var(--color-green) !important;
      }
    }
  }
`;

export default Form;
